using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a known type resolver (only Person is included).
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonSerializerOptions()
};

// 1️⃣  Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2️⃣  Probe without throwing: TryGetTypeInfo returns false when metadata isn't available.
bool found = options.TryGetTypeInfo(typeof(UnknownThing), out JsonTypeInfo? info);
Console.WriteLine($"Metadata for UnknownThing available? {found}");  // False

// Also confirm it works for a known type:
bool foundPerson = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? personInfo2);
Console.WriteLine($"Metadata for Person available? {foundPerson}, type={personInfo2?.Type.Name}");

public record Person(string Name, int Age);
public record UnknownThing(string X);

// A minimal resolver that only exposes Person.
[JsonSerializable(typeof(Person))]
internal partial class DefaultJsonSerializerOptions : JsonSerializerContext;

